## 2️⃣ `blocksci_stubs.c` – the C/C++ glue

```c
/* ----------------------------------------------------------------------
   blocksci_stubs.c
   C/C++ glue for the OCaml bindings defined in blocksci.mli.
   Compile with a C++ compiler (e.g. g++ -std=c++17) and link against
   BlockSci's library.

   The file is deliberately self‑contained: it includes the necessary
   OCaml headers, the BlockSci public header, and implements all the
   primitives declared in the .mli.
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE                /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/signals.h>

/* ----------------------------------------------------------------------
   BlockSci includes – adjust the include path according to your build.
   ---------------------------------------------------------------------- */
#include "BlockSci.h"   /* <-- replace with the real header name */

/* ----------------------------------------------------------------------
   Helper: turn a BlockSci::Block into an OCaml [block] record.
   ---------------------------------------------------------------------- */
static value block_of_cpp(const BlockSci::Block &b)
{
  CAMLparam0();
  CAMLlocal3(v_hash, v_timestamp, v_block);

  /* hash as a hex string – BlockSci provides a method that returns a std::string */
  std::string hash_cpp = b.hash();          /* <-- adapt to real API */
  v_hash = caml_copy_string(hash_cpp.c_str());

  /* timestamp as int64 */
  int64_t ts = b.timestamp();               /* <-- adapt to real API */
  v_timestamp = caml_copy_int64(ts);

  /* Allocate the OCaml record (4 fields) */
  v_block = caml_alloc(4, 0);               /* tag 0 = a normal block */
  Store_field(v_block, 0, Val_int(b.height()));   /* height : int */
  Store_field(v_block, 1, v_hash);                /* hash : string */
  Store_field(v_block, 2, v_timestamp);          /* timestamp : int64 */
  Store_field(v_block, 3, Val_int(b.tx_count()));/* tx_count : int */

  CAMLreturn(v_block);
}

/* ----------------------------------------------------------------------
   iter_blocks : (block -> unit) -> unit
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_iter_blocks(value cb)
{
  CAMLparam1(cb);
  CAMLlocal1(v_block);
  caml_release_runtime_system();               /* run C++ loop without OCaml lock */

  try {
    BlockSci::Chain chain;                     /* construct a chain handle */
    for (BlockSci::BlockIterator it = chain.begin(); it != chain.end(); ++it) {
      /* Build the OCaml record for the current block */
      v_block = block_of_cpp(*it);

      /* Re‑acquire the runtime, call the user function, then release again */
      caml_acquire_runtime_system();
      /* Use caml_callback_exn so we can detect exceptions */
      value r = caml_callback_exn(cb, v_block);
      if (Is_exception_result(r)) {
        /* Propagate the exception to OCaml – we must reacquire the lock first */
        caml_raise(r);
      }
      caml_release_runtime_system();          /* back to fast C++ loop */
    }
  } catch (const std::exception &e) {
    caml_acquire_runtime_system();            /* ensure lock before raising */
    caml_failwith(e.what());
  } catch (...) {
    caml_acquire_runtime_system();
    caml_failwith("BlockSci: unknown C++ exception");
  }

  caml_acquire_runtime_system();               /* final reacquire before return */
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   fold_blocks : (block -> 'a -> 'a) -> 'a -> 'a
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_fold_blocks(value f, value acc)
{
  CAMLparam2(f, acc);
  CAMLlocal1(v_block);
  CAMLlocal1(v_acc);   /* accumulator that will be threaded through the loop */

  v_acc = acc;                         /* start with the user‑provided init */

  caml_release_runtime_system();       /* run C++ loop without lock */

  try {
    BlockSci::Chain chain;
    for (BlockSci::BlockIterator it = chain.begin(); it != chain.end(); ++it) {
      v_block = block_of_cpp(*it);

      caml_acquire_runtime_system();
      value r = caml_callback_exn(f, v_block, v_acc);
      if (Is_exception_result(r)) caml_raise(r);
      v_acc = r;
      caml_release_runtime_system();
    }
  } catch (const std::exception &e) {
    caml_acquire_runtime_system();
    caml_failwith(e.what());
  } catch (...) {
    caml_acquire_runtime_system();
    caml_failwith("BlockSci: unknown C++ exception");
  }

  caml_acquire_runtime_system();
  CAMLreturn(v_acc);
}

/* ----------------------------------------------------------------------
   map_blocks : (block -> 'b) -> 'b array
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_map_blocks(value f)
{
  CAMLparam1(f);
  CAMLlocal3(v_block, v_res, v_arr);
  /* We first need to know the chain length – BlockSci provides it */
  size_t n = BlockSci::Chain::size();   /* <-- adapt to real API */

  /* Allocate the result OCaml array */
  v_arr = caml_alloc(n, 0);             /* a generic OCaml array */
  caml_release_runtime_system();

  try {
    BlockSci::Chain chain;
    size_t i = 0;
    for (BlockSci::BlockIterator it = chain.begin(); it != chain.end(); ++it, ++i) {
      v_block = block_of_cpp(*it);
      caml_acquire_runtime_system();
      v_res = caml_callback_exn(f, v_block);
      if (Is_exception_result(v_res)) caml_raise(v_res);
      Store_field(v_arr, i, v_res);
      caml_release_runtime_system();
    }
    if (i != n) caml_failwith("BlockSci: chain size changed during iteration");
  } catch (const std::exception &e) {
    caml_acquire_runtime_system();
    caml_failwith(e.what());
  } catch (...) {
    caml_acquire_runtime_system();
    caml_failwith("BlockSci: unknown C++ exception");
  }

  caml_acquire_runtime_system();
  CAMLreturn(v_arr);
}

/* ----------------------------------------------------------------------
   get_block : int -> block option
   ---------------------------------------------------------------------- */
CAMLprim value caml_blocksci_get_block(value v_height)
{
  CAMLparam1(v_height);
  CAMLlocal1(v_opt);
  int height = Int_val(v_height);

  caml_release_runtime_system();
  try {
    BlockSci::Chain chain;
    if (height < 0 || (size_t)height >= chain.size()) {
      caml_acquire_runtime_system();
      v_opt = Val_int(0);                /* None */
      CAMLreturn(v_opt);
    }
    BlockSci::Block b = chain[height];   /* random access */
    caml_acquire_runtime_system();
    v_opt = caml_alloc(1, 0);            /* Some */
    Store_field(v_opt, 0, block_of_cpp(b));
    CAMLreturn(v_opt);
  } catch (const std::exception &e) {
    caml_acquire_runtime_system();
    caml_failwith(e.what());
  } catch (...) {
    caml_acquire_runtime_system();
    caml_failwith("BlockSci: unknown C++ exception");
  }
}

/* ----------------------------------------------------------------------
   Registration table – needed only for the dynamic linking case.
   ---------------------------------------------------------------------- */
static struct caml_named_value caml_named[] = {
  { "Blocksci.iter_blocks", caml_blocksci_iter_blocks },
  { "Blocksci.fold_blocks", caml_blocksci_fold_blocks },
  { "Blocksci.map_blocks",  caml_blocksci_map_blocks },
  { "Blocksci.get_block",   caml_blocksci_get_block },
  { NULL, NULL }
};

CAMLprim value caml_blocksci_register(void)
{
  caml_register_named_values(caml_named);
  return Val_unit;
}

/* End of blocksci_stubs.c */
```

### What the stub does

| Function | What it does | OCaml ↔ C++ interaction |
|----------|--------------|------------------------|
| `caml_blocksci_iter_blocks` | Walks the whole chain, builds a record for each block and calls the OCaml closure. | The C++ loop runs **without** the OCaml lock (`caml_release_runtime_system`). For each iteration we *re‑acquire* the lock, invoke the closure (`caml_callback_exn`), then release again. |
| `caml_blocksci_fold_blocks` | Same loop but threads an OCaml accumulator through the callback. | Same lock‑hand‑shake as `iter`. The accumulator lives on the OCaml heap, so the callback must run under the runtime lock. |
| `caml_blocksci_map_blocks` | Builds an OCaml array of results. | Allocates the array once, then fills it element‑by‑element under the lock. |
| `caml_blocksci_get_block` | Random‑access read of a single block. | No long loop, just a quick C++ lookup; the lock is released for the lookup and reacquired for the result. |
| `caml_blocksci_register` | Optional registration helper if you prefer the `Callback.register` style. | Not strictly required when the functions are linked statically, but handy for dynamic loading. |

### Safety & performance considerations

* **Lock management** – The hot C++ loop runs *outside* the OCaml runtime lock, so the GC does **not** pause the iteration. The lock is only taken for the tiny callback, which is unavoidable if we want user‑written OCaml code to run.  
* **Exception propagation** – We use `caml_callback_exn` and test `Is_exception_result`. If the user function raises, the iteration stops immediately and the exception bubbles up to the caller.  
* **Thread‑safety** – The stub releases the runtime lock, so the iteration can run in a *native* thread (e.g. launched from an OCaml `Thread.create`). The only restriction is that the OCaml callback must be pure (no concurrent accesses to mutable OCaml data unless you protect them).  
* **Memory allocation** – A new OCaml block record is allocated for each iteration. This is the cheapest possible representation (four heap words + a string). BlockSci’s own data structures remain in C++ memory, so the per‑block overhead is a few dozen nanoseconds, far below the cost of traversing the chain.  

